Escrow verification logic:
```typescript
async function verifyEscrow(escrowPda: string, requiredUsdc: number): Promise<{ ok: boolean; balance: number; error?: string }> {
  const rpcUrl = process.env.SOLANA_RPC_URL || 'https://api.mainnet-beta.solana.com';
  const body = JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'getTokenAccountBalance', params: [escrowPda] });
  const resp = await fetch(rpcUrl, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body });
  const json = await resp.json() as any;
  if (json.error || !json.result?.value) return { ok: false, balance: 0, error: 'Escrow account not found or invalid' };
  const balance = parseFloat(json.result.value.uiAmount || '0');
  return { ok: balance >= requiredUsdc, balance };
}
